import tensorflow.compat.v1 as tf


def load_graph(string):
    tf.disable_v2_behavior()
    restored_graph_def = tf.GraphDef()
    restored_graph_def.ParseFromString(string)
    for node in restored_graph_def.node:
        if node.op == "RefSwitch":
            node.op = "Switch"
            for index, name in enumerate(node.input):
                if "moving_" in name:
                    node.input[index] = name + "/read"
        elif node.op == "AssignSub":
            node.op = "Sub"
            node.attr.pop("use_locking", None)
        elif node.op == "AssignAdd":
            node.op = "Add"
            node.attr.pop("use_locking", None)
    with tf.Graph().as_default() as graph:
        tf.import_graph_def(restored_graph_def, name="")
    y_pred = graph.get_tensor_by_name("y_pred:0")
    sess = tf.Session(graph=graph)
    point_cloud = graph.get_tensor_by_name("point_cloud:0")
    label = graph.get_tensor_by_name("label:0")
    is_training = graph.get_tensor_by_name("is_training:0")
    return sess, y_pred, point_cloud, label, is_training
